mapper.select:
SELECT DISTINCT ta.venueId, ta.venueName, ta.venueType, ta.venueCode, ta.venueJoinType, ta.STATUS, ta.handlingFee, ta.validProportion, ta.operatorTime, ta.operator, ta.chooseFlag, ta.gameNum FROM ( SELECT vi.id AS venueId, vi.venue_name AS venueName, vi.venue_type AS venueType, vi.venue_code AS venueCode, vi.venue_join_type AS venueJoinType, vi.STATUS, IFNULL(svi.handling_fee, vi.venue_proportion) AS handlingFee, IFNULL(svi.valid_proportion, vi.valid_proportion) AS validProportion, IFNULL(svi.created_time, vi.updated_time) AS operatorTime, IFNULL(svi.creator, vi.creator) AS operator, IF(vi.venue_code = svi.venue_code, 1, 0) AS chooseFlag, vi.gameNum FROM ( SELECT sv.id, sv.venue_code, sv.venue_name, sv.venue_type, sv.venue_join_type, sv.venue_proportion, sv.valid_proportion, sv.updated_time, sv.STATUS, sv.creator, (SELECT COUNT(1) FROM game_info gi WHERE gi.venue_code = sv.venue_code) AS gameNum, ROW_NUMBER() OVER (PARTITION BY sv.venue_code ORDER BY sv.id DESC) AS rn FROM venue_info sv ) vi LEFT JOIN site_venue svi ON vi.venue_code = svi.venue_code AND svi.site_code = #{vo.siteCode} WHERE vi.rn = 1 ) AS ta
AND ta.venueName = #{vo.venueName}
AND ta.venueCode = #{vo.venueCode}
AND ta.venueType = #{vo.venueType}
AND ta.status = #{vo.status}
ORDER BY ta.chooseFlag DESC, ta.status ASC, ta.operatorTime DESC

SELECT * FROM site_venue sv
LEFT JOIN site_venue_config config ON config.venue_code = sv.venue_code and config.site_code = #{siteCode}
where sv.site_code = #{siteCode}
